package com.yottastudios.ns.collabspace.space.controller;

import com.yottastudios.ns.collabspace.control.infrastructure.ControlType;
import com.yottastudios.ns.collabspace.shared.component.scanner.annotation.ApiResource;
import com.yottastudios.ns.collabspace.shared.component.scanner.annotation.GetResource;
import com.yottastudios.ns.collabspace.core.support.ResponseData;
import com.yottastudios.ns.collabspace.shared.component.scanner.annotation.PostResource;
import com.yottastudios.ns.collabspace.shared.context.SessionContext;
import com.yottastudios.ns.collabspace.shared.holder.SpaceHolder;
import com.yottastudios.ns.collabspace.control.infrastructure.permission.NodePermission;
import com.yottastudios.ns.collabspace.control.infrastructure.role.RoleConstants;
import com.yottastudios.ns.collabspace.space.manager.query.SpacePermissionPolicyQueryManager;
import com.yottastudios.ns.collabspace.space.manager.update.SpacePermissionPolicyUpdateManager;
import com.yottastudios.ns.collabspace.space.vo.SpacePermissionPolicyVo;
import com.yottastudios.ns.collabspace.space.vo.PermissionCodesAndRoleTagsVo;
import com.yottastudios.ns.collabspace.space.ro.SpacePermissionPolicySaveRo;
import com.yottastudios.ns.collabspace.shared.constants.ParamsConstants;
import io.swagger.v3.oas.annotations.tags.Tag;
import io.swagger.v3.oas.annotations.Operation;
import io.swagger.v3.oas.annotations.Parameter;
import io.swagger.v3.oas.annotations.Parameters;
import io.swagger.v3.oas.annotations.enums.ParameterIn;
import io.swagger.v3.oas.annotations.media.Schema;
import jakarta.annotation.Resource;
import org.springframework.web.bind.annotation.RestController;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RequestBody;

import java.util.Arrays;
import java.util.List;

@RestController
@Tag(name = "Space Permission")
@ApiResource(path = "/space/permission")
public class SpacePermissionController {

    @Resource
    private SpacePermissionPolicyQueryManager spacePermissionPolicyQueryManager;

    @Resource
    private SpacePermissionPolicyUpdateManager spacePermissionPolicyUpdateManager;

    @GetResource(path = "/listCodesAndRoleTags", requiredPermission = false)
    @Operation(summary = "List Codes and RoleTags")
    public ResponseData<PermissionCodesAndRoleTagsVo> listCodesAndRoleTags(@RequestParam(required = false) Integer type) {
        // type目前只有一个不做处理, 用于未来多个ControlType时的查询
        List<String> codes = Arrays.stream(NodePermission.values()).map(NodePermission::getCode).toList();
        List<String> roleTags = List.of(
                RoleConstants.SpaceNode.READER,
                RoleConstants.SpaceNode.EDITOR,
                RoleConstants.SpaceNode.MANAGER
        );
        return ResponseData.success(PermissionCodesAndRoleTagsVo.builder().codes(codes).roleTags(roleTags).build());
    }

    @GetResource(path = "/listPolicies")
    @Parameters({
            @Parameter(name = ParamsConstants.SPACE_ID, description = "space id", required = true,
                    schema = @Schema(type = "string"), in = ParameterIn.HEADER, example = "spcVyED5StRev"),
    })
    @Operation(summary = "List Space Permission Policies by spaceId and type")
    public ResponseData<List<SpacePermissionPolicyVo>> listPolicies(@RequestParam(required = false) Integer type) {
        String spaceId = SpaceHolder.get();
        Integer t = type != null ? type : ControlType.SPACE_NODE.getVal();
        return ResponseData.success(spacePermissionPolicyQueryManager.listPolicies(spaceId, t));
    }

    @PostResource(path = "/savePolicies", requiredSpaceAdmin = true)
    @Parameters({
            @Parameter(name = ParamsConstants.SPACE_ID, description = "space id", required = true,
                    schema = @Schema(type = "string"), in = ParameterIn.HEADER, example = "spcVyED5StRev"),
    })
    @Operation(summary = "Save Space Permission Policies")
    public ResponseData<Void> savePolicies(@RequestBody SpacePermissionPolicySaveRo ro) {
        String spaceId = SpaceHolder.get();
        Long userId = SessionContext.getUserId();
        spacePermissionPolicyUpdateManager.savePolicies(spaceId, userId, ro.getPolicies());
        return ResponseData.success();
    }

    @PostResource(path = "/savePoliciesToAllOwnedSpaces", requiredPermission = false)
    @Operation(summary = "Save Space Permission Policies to All Spaces User Own")
    public ResponseData<Void> savePoliciesToAllOwnedSpaces(@RequestBody SpacePermissionPolicySaveRo ro) {
        Long userId = SessionContext.getUserId();
        spacePermissionPolicyUpdateManager.savePoliciesToAllOwnedSpaces(userId, ro.getPolicies(),
                ro.getAllowAcrossSpaceRel(),ro.getAllowAcrossSpaceAcquire());
        return ResponseData.success();
    }

}

