package com.yottastudios.ns.collabspace.space.manager.update.impl;

import com.yottastudios.ns.collabspace.control.infrastructure.ControlType;
import com.yottastudios.ns.collabspace.core.exception.BusinessException;
import com.yottastudios.ns.collabspace.interfaces.eventbus.facade.EventBusFacade;
import com.yottastudios.ns.collabspace.interfaces.eventbus.model.spacepolicy.SpacePolicyChangedEvent;
import com.yottastudios.ns.collabspace.space.manager.update.SpacePermissionPolicyUpdateManager;
import com.yottastudios.ns.collabspace.control.infrastructure.permission.NodePermission;
import com.yottastudios.ns.collabspace.control.infrastructure.role.RoleConstants;
import com.yottastudios.ns.collabspace.core.exception.BusinessException;
import com.yottastudios.ns.collabspace.grpc.IApitableGrpcClientService;
import com.yottastudios.ns.collabspace.space.dto.SpaceAcrossConfigDto;
import com.yottastudios.ns.collabspace.space.entity.SpaceEntity;
import com.yottastudios.ns.collabspace.space.entity.SpacePermissionPolicyEntity;
import com.yottastudios.ns.collabspace.space.enums.SpaceException;
import com.yottastudios.ns.collabspace.space.enums.SpacePermissionException;
import com.yottastudios.ns.collabspace.space.manager.update.SpacePermissionPolicyUpdateManager;
import com.yottastudios.ns.collabspace.space.ro.SpacePermissionPolicyItemRo;
import com.yottastudios.ns.collabspace.space.service.ISpacePermissionPolicyService;
import com.yottastudios.ns.collabspace.space.service.ISpaceService;
import jakarta.annotation.Resource;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.*;

@Service
public class SpacePermissionPolicyUpdateManagerImpl implements SpacePermissionPolicyUpdateManager {

    @Resource
    private ISpaceService spaceService;

    @Resource
    private ISpacePermissionPolicyService spacePermissionPolicyService;

    @Resource
    private EventBusFacade eventBusFacade;

    @Resource
    private IApitableGrpcClientService apitableGrpcClientService;

    @Override
    @Transactional
    public void savePolicies(String spaceId, Long userId, List<SpacePermissionPolicyItemRo> policies) {
        if (policies == null || policies.isEmpty()) {
            throw new BusinessException(SpacePermissionException.EMPTY_INPUT);
        }

        SpaceEntity space = spaceService.getBySpaceId(spaceId);
        if (space == null) {
            throw new BusinessException(SpaceException.NOT_EXIST);
        }
        if (space.getOwner() == null || !space.getOwner().equals(userId)) {
            throw new BusinessException(SpacePermissionException.UNAUTHORIZED);
        }

        // 目前只考虑RoleConstants.SpaceNode
        Set<String> validRoles = Set.of(
                RoleConstants.SpaceNode.READER,
                RoleConstants.SpaceNode.EDITOR,
                RoleConstants.SpaceNode.MANAGER
        );

        Set<String> validCodes = new HashSet<>();
        for (NodePermission p : NodePermission.values()) {
            validCodes.add(p.getCode());
        }

        for (SpacePermissionPolicyItemRo vo : policies) {
            if (vo.getMinRoleTag() == null || !validRoles.contains(vo.getMinRoleTag())) {
                throw new BusinessException(SpacePermissionException.INVALID_ROLE);
            }
            if (vo.getCode() == null || !validCodes.contains(vo.getCode())) {
                throw new BusinessException(SpacePermissionException.INVALID_CODE);
            }
        }

        Integer type = policies.getFirst().getType() != null ? policies.getFirst().getType() : ControlType.SPACE_NODE.getVal();
        List<SpacePermissionPolicyEntity> existing = spacePermissionPolicyService.listByTypeAndSpaceIds(type, List.of(spaceId));
        Map<String, SpacePermissionPolicyEntity> existingByCode = new HashMap<>();
        for (SpacePermissionPolicyEntity e : existing) {
            existingByCode.put(e.getCode(), e);
        }

        List<SpacePermissionPolicyEntity> toInsert = new ArrayList<>();
        List<SpacePermissionPolicyEntity> toUpdate = new ArrayList<>();
        for (SpacePermissionPolicyItemRo vo : policies) {
            String code = vo.getCode();
            SpacePermissionPolicyEntity found = existingByCode.get(code);
            if (found == null) {
                toInsert.add(SpacePermissionPolicyEntity.builder()
                        .spaceId(spaceId)
                        .code(code)
                        .type(vo.getType() != null ? vo.getType() : type)
                        .minRoleTag(vo.getMinRoleTag())
                        .build());
            } else {
                found.setMinRoleTag(vo.getMinRoleTag());
                toUpdate.add(found);
            }
        }

        if (!toInsert.isEmpty()) spacePermissionPolicyService.saveBatch(toInsert);
        if (!toUpdate.isEmpty()) spacePermissionPolicyService.updateBatchById(toUpdate);

        eventBusFacade.onEventAfterCommit(new SpacePolicyChangedEvent(spaceId));
    }

    @Transactional
    @Override
    public void savePoliciesToAllOwnedSpaces(Long userId, List<SpacePermissionPolicyItemRo> policies,
                                             Boolean allowAcrossSpaceRel,Boolean allowAcrossSpaceAcquire) {
        List<SpaceEntity> ownSpaces = spaceService.getOwnSpaces(userId);
        for (SpaceEntity space : ownSpaces) {
            // 可以改为批量操作优化性能
            savePolicies(space.getSpaceId(), userId, policies);
        }

        List<SpaceAcrossConfigDto> dtoList = new ArrayList<>();
        List<String> spaceIdList = ownSpaces.stream().map(SpaceEntity::getSpaceId).toList();
        spaceIdList.forEach(spaceId -> {
            dtoList.add(SpaceAcrossConfigDto.builder()
                    .spaceId(spaceId)
                    .allowAcrossSpaceRel(allowAcrossSpaceRel)
                    .allowAcrossSpaceAcquire(allowAcrossSpaceAcquire).build());
        });

        apitableGrpcClientService.batchUpdateAcrossConfig(dtoList);

    }
}

