 2→import React from 'react';
 3→import { useParams } from 'react-router';
 4→
 5→import { t, tRaw } from '@/i18n';
 6→import { useGetCrossTablePermissionsQuery, useSaveCrossTablePermissionsMutation } from '@/store/query/space';
 7→
 8→import styles from './index.module.css';
 9→
10→const permissionOptions = [
11→  {
12→    label: t('allow'),
13→    value: true,
14→  },
15→  {
16→    label: t('notAllow'),
17→    value: false,
18→  },
19→];
20→export const SecurityBlock: React.FC = () => {
21→  const spaceId = useParams().spaceId!;
22→  const { data: crossPolicies, isFetching: isCrossFetching } = useGetCrossTablePermissionsQuery({ spaceId });
23→  const [saveCrossPermissionPolicies, { isLoading: saveCrossLoading }] = useSaveCrossTablePermissionsMutation();
24→
25→  const loading = isCrossFetching || saveCrossLoading;
26→  return (
27→    <section style={{ gridArea: 'security' }} className={styles.customPermPage}>
28→      <Typography.Title level={4}>{t('dataSecurity')}</Typography.Title>
29→      <div>
30→        {tRaw<React.ReactNode[]>('allowTableRelate', {
31→          perm: (
32→            <Select
33→              variant="borderless"
34→              disabled={loading}
35→              value={crossPolicies?.allowAcrossSpaceRel}
36→              options={permissionOptions}
37→              onChange={(value) => saveCrossPermissionPolicies({ permissions: { ...crossPolicies, allowAcrossSpaceRel: value }, spaceId })}
