import { Select, Typography } from 'antd';
import React from 'react';
import { useParams } from 'react-router';

import { t, tRaw } from '@/i18n';
import { useGetCrossTablePermissionsQuery, useSaveCrossTablePermissionsMutation } from '@/store/query/space';

import styles from './index.module.css';

const permissionOptions = [
  {
    label: t('allow'),
    value: true,
  },
  {
    label: t('notAllow'),
    value: false,
  },
];
export const SecurityBlock: React.FC = () => {
  const spaceId = useParams().spaceId!;
  const { data: crossPolicies, isFetching: isCrossFetching } = useGetCrossTablePermissionsQuery({ spaceId });
  const [saveCrossPermissionPolicies, { isLoading: saveCrossLoading }] = useSaveCrossTablePermissionsMutation();

  const loading = isCrossFetching || saveCrossLoading;
  return (
    <section style={{ gridArea: 'security' }} className={styles.customPermPage}>
      <Typography.Title level={4}>{t('dataSecurity')}</Typography.Title>
      <div>
        {tRaw<React.ReactNode[]>('allowTableRelate', {
          perm: (
            <Select
              variant="borderless"
              disabled={loading}
              value={crossPolicies?.allowAcrossSpaceRel}
              options={permissionOptions}
              onChange={(value) => saveCrossPermissionPolicies({ permissions: { ...crossPolicies, allowAcrossSpaceRel: value }, spaceId })}
            />
          ),
        }).map((it, index) => <React.Fragment key={index}>{it}</React.Fragment>)}
      </div>
      <div>
        {tRaw<React.ReactNode[]>('allowTableDataRelate', {
          perm: (
            <Select
              variant="borderless"
              disabled={loading}
              value={crossPolicies?.allowAcrossSpaceAcquire}
              options={permissionOptions}
              onChange={(value) => saveCrossPermissionPolicies({ permissions: { ...crossPolicies, allowAcrossSpaceAcquire: value }, spaceId })}
            />
          ),
        }).map((it, index) => <React.Fragment key={index}>{it}</React.Fragment>)}
      </div>
    </section>
  );
};

