import { Select, Table, TableColumnsType, Typography } from 'antd';
import React, { useMemo } from 'react';
import { useParams } from 'react-router';

import { SpaceNodeRole } from '@/common/api/node';
import { t } from '@/i18n';
import { ISpacePermissionPolicyVo, useGetPermissionPoliciesQuery, useSavePermissionPoliciesMutation } from '@/store/query/space';
import { INodePermissions } from '@/types/space';

import styles from './index.module.css';

interface IDocPermItem {
  label: string;
  key: keyof INodePermissions;
  optionsType: 'edit' | 'read';
}

const dataSource: IDocPermItem[] = [
  {
    label: t('createAndEditDocuments'),
    key: 'childCreatable',
    optionsType: 'edit',
  },
  {
    label: t('renameDocuments'),
    key: 'renamable',
    optionsType: 'edit',
  },
  {
    label: t('deleteDocuments'),
    key: 'removable',
    optionsType: 'edit',
  },
  {
    label: t('shareDocuments'),
    key: 'sharable',
    optionsType: 'edit',
  },
  {
    label: t('downloadDocuments'),
    key: 'exportable',
    optionsType: 'read',
  },
];

const defaultPolicyMap: Partial<Record<keyof INodePermissions, SpaceNodeRole>> = {
  childCreatable: SpaceNodeRole.Editor,
  renamable: SpaceNodeRole.Editor,
  removable: SpaceNodeRole.Editor,
  sharable: SpaceNodeRole.Editor,
  exportable: SpaceNodeRole.Editor,
};

function createSpaceNodePolicyMap(policies: ISpacePermissionPolicyVo[]) {
  const result = { ...defaultPolicyMap };
  for (const policy of policies) {
    if (policy.type === 0) {
      result[policy.code] = policy.minRoleTag;
    }
  }
  return result;
}

const RoleOptionMap = {
  [SpaceNodeRole.Editor]: { label: t('roleEditable'), value: SpaceNodeRole.Editor },
  [SpaceNodeRole.Manager]: { label: t('roleManageable'), value: SpaceNodeRole.Manager },
  [SpaceNodeRole.Reader]: { label: t('roleReadable'), value: SpaceNodeRole.Reader },
};
const editOptions = [RoleOptionMap[SpaceNodeRole.Editor], RoleOptionMap[SpaceNodeRole.Manager]];
const readOptions = [RoleOptionMap[SpaceNodeRole.Reader], RoleOptionMap[SpaceNodeRole.Editor], RoleOptionMap[SpaceNodeRole.Manager]];

export const DocPermSetting: React.FC = () => {
  const spaceId = useParams().spaceId!;
  const { data: policies, isFetching: isFetching } = useGetPermissionPoliciesQuery({ spaceId, type: 0 });
  const policyMap = useMemo(() => policies && createSpaceNodePolicyMap(policies), [policies]);
  const [savePermissionPolicies, { isLoading: saveLoading }] = useSavePermissionPoliciesMutation();
  const loading = saveLoading || isFetching;

  const tableColumns = useMemo<TableColumnsType<IDocPermItem>>(() => [
    {
      title: t('operations'),
      align: 'center',
      dataIndex: 'label',
    },
    {
      title: t('documentPermissionRequirements'),
      align: 'center',
      render: (_, record) => {
        return (
          <Select
            variant="borderless"
            options={record.optionsType === 'edit' ? editOptions : readOptions}
            disabled={loading}
            value={policyMap?.[record.key]}
            onChange={(value) => savePermissionPolicies({ policies: [{ code: record.key, type: 0, minRoleTag: value }], spaceId })}
          />
        );
      },
    },
  ], [loading, policyMap, savePermissionPolicies, spaceId]);
  return (
    <section style={{ gridArea: 'perm' }} className={styles.customPermPage}>
      <Typography.Title style={{ marginBottom: 0 }} level={4}>{t('docOperationRestrictions')}</Typography.Title>
      <Typography.Text type="secondary">{t('docOperationRestrictionsDesc')}</Typography.Text>
      <Table
        size="small"
        rowHoverable={false}
        pagination={false}
        columns={tableColumns}
        dataSource={dataSource}
        loading={loading}
      />
    </section>
  );
};

