  1→import { useMemo } from 'react';
  2→
  3→import type { ISpaceSecuritySetting } from '@/common/api/apitable/space';
  4→import type { SpaceNodeRole } from '@/common/api/node';
  5→import type { IMainAdminInfo, INodePermissions, ISpace, ISpaceInfo } from '@/types/space';
  6→
  7→import { aioApi } from './api';
  8→
  9→interface ISpaceWithAdminInfo extends ISpace {
 10→  /** 是否空间主管理员（owner） */
 11→  isMainAdmin: boolean;
 12→  /** 是否文件管理员（MANAGE_WORKBENCH） */
 13→  isWorkbenchAdmin: boolean;
 14→  /** 是否成员管理员（MANAGE_MEMBER） */
 15→  isMemberAdmin: boolean;
 16→}
 17→
 18→export interface ISpacePermissionPolicyVo {
 19→  /** Permission Code */
 20→  code: keyof INodePermissions;
 21→  /** Control Type, default 0:SpaceNode */
 22→  type: number;
 23→  /** Permission Code's minRoleTag */
 24→  minRoleTag: SpaceNodeRole;
 25→}
 26→
 27→export interface ICrossTablePermissionVo {
 28→  allowAcrossSpaceRel: boolean;
 29→  allowAcrossSpaceAcquire: boolean;
 30→}
 31→
 32→/** 超管工具-空间站列表项 */
 33→export interface ISuperSpaceVo {
 34→  isForbid: boolean;
 35→  memberCount: number;
 36→  spaceId: string;
 37→  spaceName: string;
 38→}
 39→
 40→/**
 41→ * 空间站、空间站管理后台、空间站设置项
 42→ * - tags
 43→ *   - SpaceInfo - 空间站
 44→ *     - ${spaceId} - 空间站信息
 45→ *     - LIST - 空间站列表
 46→ *     - SECURITY_SETTING-${spaceId} - 空间站安全设置
 47→ *   - SpaceCustomPerm 自定义权限设置
 48→ */
 49→export const spaceApi = aioApi.injectEndpoints({
 50→  endpoints: (build) => ({
 51→    getSpaceList: build.query<{
 52→      /** 我的空间站 */
 53→      managedSpaces: ISpaceWithAdminInfo[];
 54→      /** 共享空间站 */
 55→      joinedSpaces: ISpaceWithAdminInfo[];
 56→      /** 已停用空间站 */
 57→      forbidSpaces: ISpaceWithAdminInfo[];
 58→    }, void>({
 59→      query: () => ({ url: 'api/v1/space/listSpace' }),
 60→      providesTags: (res) => res
 61→        ? [
 62→            ...res.managedSpaces.map((it) => ({ type: 'SpaceInfo' as const, id: it.spaceId })),
 63→            ...res.joinedSpaces.map((it) => ({ type: 'SpaceInfo' as const, id: it.spaceId })),
 64→            ...res.forbidSpaces.map((it) => ({ type: 'SpaceInfo' as const, id: it.spaceId })),
 65→            { type: 'SpaceInfo' as const, id: 'LIST' },
 66→          ]
 67→        : [],
 68→    }),
 69→    updateHiddenInfo: build.mutation<void, { spaceId: string; hidden: boolean }>({
 70→      query: ({ spaceId, hidden }) => ({
 71→        url: `api/v1/space/${hidden ? 'del' : 'cancel'}?spaceId=${spaceId}`,
 72→        method: 'POST',
 73→      }),
 74→      invalidatesTags: (_res, _err, req) => [{ type: 'SpaceInfo', id: req.spaceId }],
 75→    }),
 76→    /** 创建空间站 */
 77→    createSpace: build.mutation<ISpace, { name: string }>({
 78→      query: (data) => ({
 79→        url: 'api/v1/space/createSpace',
 80→        method: 'POST',
 81→        data,
 82→      }),
 83→      invalidatesTags: [{ type: 'SpaceInfo', id: 'LIST' }],
 84→    }),
 85→    getSpaceInfo: build.query<ISpaceInfo, { spaceId: string }>({
 86→      query: ({ spaceId }) => `api/v1/space/spaceInfo/${spaceId}`,
 87→      providesTags: (res) => res ? [{ type: 'SpaceInfo', id: res.spaceId }] : [],
 88→    }),
 89→    renameSpace: build.mutation<void, { newName: string; spaceId: string }>({
 90→      query: ({ newName, spaceId }) => ({
 91→        url: 'api/v1/space/renameSpace',
 92→        method: 'POST',
 93→        data: {
 94→          newName,
 95→        },
 96→        headers: {
 97→          'x-space-id': spaceId,
 98→        },
 99→      }),
100→      invalidatesTags: (_res, _err, req) => [{ type: 'SpaceInfo', id: req.spaceId }],
101→    }),
102→    getManagedSpacesForMigration: build.query<ISpace[], void>({
103→      query: () => 'api/v1/spaceNode/migration/managedSpaces',
104→      providesTags: (res) => res ? [...res.map((it) => ({ type: 'SpaceInfo' as const, id: it.spaceId })), { type: 'SpaceInfo', id: 'LIST' }] : [],
105→    }),
106→    listSpaceBySuper: build.query<{
107→      pages: number;
108→      pageNum: number;
109→      total: number;
110→      records: ISuperSpaceVo[];
111→    }, void, void>({
112→      query: () => ({
113→        url: 'api/v1/space/listSpaceBySuper',
114→        data: { pageNum: 1, pageSize: 9999 },
115→      }),
116→      providesTags: (res) => res
117→        ? [
118→            ...res.records
119→              .map((it) => ({ type: 'SpaceInfo' as const, id: it.spaceId })),
120→            { type: 'SpaceInfo', id: 'LIST' },
121→          ]
122→        : [],
123→    }),
124→    replaceManagerBySuper: build.mutation<void, { spaceId: string; email: string }>({
125→      query: (data) => ({
126→        url: 'api/v1/space/replaceManagerBySuper',
127→        method: 'POST',
128→        data,
129→        raw: true, // 忽略500信息, 消息通知失败会导致500
130→      }),
131→      invalidatesTags: (_res, err, args) => err ? [] : [{ type: 'SpaceInfo', id: args.spaceId }, { type: 'Member', id: 'LIST' }],
132→    }),
133→    getSpaceSecuritySetting: build.query<ISpaceSecuritySetting, string>({
134→      query: (spaceId) => ({
135→        url: `apitable/api/v1/space/features`,
136→        headers: {
137→          'x-space-id': spaceId,
138→        },
139→      }),
140→      providesTags: (_res, err, spaceId) => err ? [] : [{ type: 'SpaceInfo', id: `SECURITY_SETTING-${spaceId}` }],
141→    }),
142→    updateSpaceSecuritySetting: build.mutation<void, ISpaceSecuritySetting & { spaceId: string }>({
143→      query: ({ spaceId, ...data }) => ({
144→        url: `apitable/api/v1/space/updateSecuritySetting`,
145→        method: 'POST',
146→        data,
147→        headers: {
148→          'x-space-id': spaceId,
149→        },
150→      }),
151→      invalidatesTags: (_res, err, args) => err ? [] : [{ type: 'SpaceInfo', id: `SECURITY_SETTING-${args.spaceId}` }],
152→    }),
153→    /** 不需要调用，返回值就是类型中的全部值 */
154→    listPermissionCodesAndRoleTags: build.query<{
155→      /** All NodePermission codes */
156→      codes: (keyof INodePermissions)[];
157→      /** Valid role tags of RoleConstants.SpaceNode */
158→      roleTags: SpaceNodeRole[];
159→    }, { type?: number } | void>({
160→      query: (data) => ({
161→        url: 'api/v1/space/permission/listCodesAndRoleTags',
162→        data,
163→      }),
164→    }),
165→    getPermissionPolicies: build.query<ISpacePermissionPolicyVo[], {
166→      spaceId: string;
167→      type?: number;
168→    }>({
169→      query: ({ spaceId, ...data }) => ({
170→        url: 'api/v1/space/permission/listPolicies',
171→        data,
172→        headers: {
173→          'x-space-id': spaceId,
174→        },
175→      }),
176→      providesTags: (res, _err, args) => res ? [{ type: 'SpaceCustomPerm', id: args.spaceId }] : [],
177→    }),
178→    savePermissionPolicies: build.mutation<void, {
179→      policies: ISpacePermissionPolicyVo[];
180→      allowAcrossSpaceRel?: boolean;
181→      allowAcrossSpaceAcquire?: boolean;
182→      spaceId: string;
183→    }>({
184→      query: ({ spaceId, ...data }) => ({
185→        url: 'api/v1/space/permission/savePolicies',
186→        data,
187→        method: 'POST',
188→        headers: {
189→          'x-space-id': spaceId,
190→        },
191→      }),
192→      invalidatesTags: (_res, err, args) => err ? [] : [{ type: 'SpaceCustomPerm', id: args.spaceId }],
193→    }),
194→    getCrossTablePermissions: build.query<ICrossTablePermissionVo, {
195→      spaceId: string;
196→      type?: number;
197→    }>({
198→      query: ({ spaceId, ...data }) => ({
199→        url: 'apitable/api/v1/space/getSpaceAcrossConfig',
200→        data,
201→        headers: {
202→          'x-space-id': spaceId,
203→        },
204→      }),
205→      providesTags: (res, _err, args) => res ? [{ type: 'SpaceCustomPerm', id: `ACROSS-${args.spaceId}` }] : [],
206→    }),
207→    saveCrossTablePermissions: build.mutation<void, {
208→      permissions: Partial<ICrossTablePermissionVo>;
209→      spaceId: string;
210→    }>({
211→      query: ({ spaceId, ...data }) => ({
212→        url: 'apitable/api/v1/space/updateSpaceAcrossConfig',
213→        data: data.permissions,
214→        method: 'POST',
215→        headers: {
216→          'x-space-id': spaceId,
217→        },
218→      }),
219→      invalidatesTags: (_res, err, args) => err ? [] : [{ type: 'SpaceCustomPerm', id: `ACROSS-${args.spaceId}` }],
220→    }),
221→    savePoliciesToAllOwnedSpaces: build.mutation<void, { policies: ISpacePermissionPolicyVo[] }>({
222→      query: (data) => ({
223→        url: 'api/v1/space/permission/savePoliciesToAllOwnedSpaces',
224→        data,
225→        method: 'POST',
226→      }),
227→      invalidatesTags: (_res, err) => err ? [] : [{ type: 'SpaceCustomPerm' }],
228→    }),
229→    getSpaceManager: build.query<IMainAdminInfo, { spaceId: string }>({
230→      query: ({ spaceId }) => ({
231→        url: 'apitable/api/v1/space/manager',
232→        headers: {
233→          'x-space-id': spaceId,
234→        },
235→      }),
236→      providesTags: (_res, err, args) => err ? [] : [{ type: 'SpaceInfo', id: args.spaceId }],
237→    }),
238→  }),
239→  overrideExisting: 'throw',
240→});
241→
242→export const {
243→  /** 获取空间站列表 */
244→  useGetSpaceListQuery,
245→  /** 修改空间站停用状态 */
246→  useUpdateHiddenInfoMutation,
247→  /** 创建空间站 */
248→  useCreateSpaceMutation,
249→  /** 获取空间站信息 */
250→  useGetSpaceInfoQuery,
251→  /** 修改空间站名称 */
252→  useRenameSpaceMutation,
253→  /** 获取可迁移到的空间站列表，复制外网文档到内网用 */
254→  useGetManagedSpacesForMigrationQuery,
255→  /** 超级管理员获取所有空间站列表 */
256→  useListSpaceBySuperQuery,
257→  /** 超级管理员修改空间站管理员 */
258→  useReplaceManagerBySuperMutation,
259→  /** 获取空间站安全设置 */
260→  useGetSpaceSecuritySettingQuery,
261→  /** 修改空间站安全设置 */
262→  useUpdateSpaceSecuritySettingMutation,
263→  /** 获取权限和角色枚举值列表 */
264→  // useListPermissionCodesAndRoleTagsQuery,
265→  /** 获取空间站自定义权限配置 */
266→  useGetPermissionPoliciesQuery,
267→  /** 保存空间站自定义权限配置 */
268→  useSavePermissionPoliciesMutation,
269→  /** 保存空间站自定义权限配置到主管理员的所有空间站 */
270→  useSavePoliciesToAllOwnedSpacesMutation,
271→  /** 获取空间站跨表权限 */
272→  useGetCrossTablePermissionsQuery,
273→  /** 保存空间站跨表权限 */
274→  useSaveCrossTablePermissionsMutation,
275→  /** 获取空间站主管理员信息 */
276→  useGetSpaceManagerQuery,
277→} = spaceApi;
278→
279→/** 从空间站列表获取空间站信息 */
280→export const useSpaceListInfo = (spaceId: string, showForbidSpace = false) => {
281→  const { data } = useGetSpaceListQuery();
282→  return useMemo(() => {
283→    if (!data) return undefined;
284→    return data.managedSpaces.find((it) => it.spaceId === spaceId)
285→      ?? data.joinedSpaces.find((it) => it.spaceId === spaceId)
286→      ?? (showForbidSpace ? data.forbidSpaces.find((it) => it.spaceId === spaceId) : undefined);
287→  }, [data, showForbidSpace, spaceId]);
288→};
