interface ISpaceWithAdminInfo extends ISpace {
  /** 是否空间主管理员（owner） */
  isMainAdmin: boolean;
  /** 是否文件管理员（MANAGE_WORKBENCH） */
  isWorkbenchAdmin: boolean;
  /** 是否成员管理员（MANAGE_MEMBER） */
  isMemberAdmin: boolean;
}

export interface ISpacePermissionPolicyVo {
  /** Permission Code */
  code: keyof INodePermissions;
  /** Control Type, default 0:SpaceNode */
  type: number;
  /** Permission Code's minRoleTag */
  minRoleTag: SpaceNodeRole;
}

export interface ICrossTablePermissionVo {
  allowAcrossSpaceRel: boolean;
  allowAcrossSpaceAcquire: boolean;
}

/** 超管工具-空间站列表项 */
export interface ISuperSpaceVo {
  isForbid: boolean;
  memberCount: number;
  spaceId: string;
  spaceName: string;
}

/**
 * 空间站、空间站管理后台、空间站设置项
 * - tags
 *   - SpaceInfo - 空间站
 *     - ${spaceId} - 空间站信息
 *     - LIST - 空间站列表
 *     - SECURITY_SETTING-${spaceId} - 空间站安全设置
 *   - SpaceCustomPerm 自定义权限设置
 */
export const spaceApi = aioApi.injectEndpoints({
  endpoints: (build) => ({
    getSpaceList: build.query<{
      /** 我的空间站 */
      managedSpaces: ISpaceWithAdminInfo[];
      /** 共享空间站 */
      joinedSpaces: ISpaceWithAdminInfo[];
      /** 已停用空间站 */
      forbidSpaces: ISpaceWithAdminInfo[];
    }, void>({
      query: () => ({ url: 'api/v1/space/listSpace' }),
      providesTags: (res) => res
        ? [
            ...res.managedSpaces.map((it) => ({ type: 'SpaceInfo' as const, id: it.spaceId })),
            ...res.joinedSpaces.map((it) => ({ type: 'SpaceInfo' as const, id: it.spaceId })),
            ...res.forbidSpaces.map((it) => ({ type: 'SpaceInfo' as const, id: it.spaceId })),
            { type: 'SpaceInfo' as const, id: 'LIST' },
          ]
        : [],
    }),
    updateHiddenInfo: build.mutation<void, { spaceId: string; hidden: boolean }>({
      query: ({ spaceId, hidden }) => ({
        url: `api/v1/space/${hidden ? 'del' : 'cancel'}?spaceId=${spaceId}`,
        method: 'POST',
      }),
      invalidatesTags: (_res, _err, req) => [{ type: 'SpaceInfo', id: req.spaceId }],
    }),
    /** 创建空间站 */
    createSpace: build.mutation<ISpace, { name: string }>({
      query: (data) => ({
        url: 'api/v1/space/createSpace',
        method: 'POST',
        data,
      }),
      invalidatesTags: [{ type: 'SpaceInfo', id: 'LIST' }],
    }),
    getSpaceInfo: build.query<ISpaceInfo, { spaceId: string }>({
      query: ({ spaceId }) => `api/v1/space/spaceInfo/${spaceId}`,
      providesTags: (res) => res ? [{ type: 'SpaceInfo', id: res.spaceId }] : [],
    }),
    renameSpace: build.mutation<void, { newName: string; spaceId: string }>({
      query: ({ newName, spaceId }) => ({
        url: 'api/v1/space/renameSpace',
        method: 'POST',
        data: {
          newName,
        },
        headers: {
          'x-space-id': spaceId,
        },
      }),
      invalidatesTags: (_res, _err, req) => [{ type: 'SpaceInfo', id: req.spaceId }],
    }),
    getManagedSpacesForMigration: build.query<ISpace[], void>({
      query: () => 'api/v1/spaceNode/migration/managedSpaces',
      providesTags: (res) => res ? [...res.map((it) => ({ type: 'SpaceInfo' as const, id: it.spaceId })), { type: 'SpaceInfo', id: 'LIST' }] : [],
    }),
    listSpaceBySuper: build.query<{
      pages: number;
      pageNum: number;
      total: number;
      records: ISuperSpaceVo[];
    }, void, void>({
      query: () => ({
        url: 'api/v1/space/listSpaceBySuper',
        data: { pageNum: 1, pageSize: 9999 },
      }),
      providesTags: (res) => res
        ? [
            ...res.records
              .map((it) => ({ type: 'SpaceInfo' as const, id: it.spaceId })),
            { type: 'SpaceInfo', id: 'LIST' },
          ]
        : [],
    }),
    replaceManagerBySuper: build.mutation<void, { spaceId: string; email: string }>({
      query: (data) => ({
        url: 'api/v1/space/replaceManagerBySuper',
        method: 'POST',
        data,
        raw: true, // 忽略500信息, 消息通知失败会导致500
      }),
      invalidatesTags: (_res, err, args) => err ? [] : [{ type: 'SpaceInfo', id: args.spaceId }, { type: 'Member', id: 'LIST' }],
    }),
    getSpaceSecuritySetting: build.query<ISpaceSecuritySetting, string>({
      query: (spaceId) => ({
        url: `apitable/api/v1/space/features`,
        headers: {
          'x-space-id': spaceId,
        },
      }),
      providesTags: (_res, err, spaceId) => err ? [] : [{ type: 'SpaceInfo', id: `SECURITY_SETTING-${spaceId}` }],
    }),
    updateSpaceSecuritySetting: build.mutation<void, ISpaceSecuritySetting & { spaceId: string }>({
      query: ({ spaceId, ...data }) => ({
        url: `apitable/api/v1/space/updateSecuritySetting`,
        method: 'POST',
        data,
        headers: {
          'x-space-id': spaceId,
        },
      }),
      invalidatesTags: (_res, err, args) => err ? [] : [{ type: 'SpaceInfo', id: `SECURITY_SETTING-${args.spaceId}` }],
    }),
    /** 不需要调用，返回值就是类型中的全部值 */
    listPermissionCodesAndRoleTags: build.query<{
      /** All NodePermission codes */
      codes: (keyof INodePermissions)[];
      /** Valid role tags of RoleConstants.SpaceNode */
      roleTags: SpaceNodeRole[];
    }, { type?: number } | void>({
      query: (data) => ({
        url: 'api/v1/space/permission/listCodesAndRoleTags',
        data,
      }),
    }),
    getPermissionPolicies: build.query<ISpacePermissionPolicyVo[], {
      spaceId: string;
      type?: number;
    }>({
      query: ({ spaceId, ...data }) => ({
        url: 'api/v1/space/permission/listPolicies',
        data,
        headers: {
          'x-space-id': spaceId,
        },
      }),
      providesTags: (res, _err, args) => res ? [{ type: 'SpaceCustomPerm', id: args.spaceId }] : [],
    }),
    savePermissionPolicies: build.mutation<void, {
      policies: ISpacePermissionPolicyVo[];
      allowAcrossSpaceRel?: boolean;
      allowAcrossSpaceAcquire?: boolean;
      spaceId: string;
    }>({
      query: ({ spaceId, ...data }) => ({
        url: 'api/v1/space/permission/savePolicies',
        data,
        method: 'POST',
        headers: {
          'x-space-id': spaceId,
        },
      }),
      invalidatesTags: (_res, err, args) => err ? [] : [{ type: 'SpaceCustomPerm', id: args.spaceId }],
    }),
    getCrossTablePermissions: build.query<ICrossTablePermissionVo, {
      spaceId: string;
      type?: number;
    }>({
      query: ({ spaceId, ...data }) => ({
        url: 'apitable/api/v1/space/getSpaceAcrossConfig',
        data,
        headers: {
          'x-space-id': spaceId,
        },
      }),
      providesTags: (res, _err, args) => res ? [{ type: 'SpaceCustomPerm', id: `ACROSS-${args.spaceId}` }] : [],
    }),
    saveCrossTablePermissions: build.mutation<void, {
      permissions: Partial<ICrossTablePermissionVo>;
      spaceId: string;
    }>({
      query: ({ spaceId, ...data }) => ({
        url: 'apitable/api/v1/space/updateSpaceAcrossConfig',
        data: data.permissions,
        method: 'POST',
        headers: {
          'x-space-id': spaceId,
        },
      }),
      invalidatesTags: (_res, err, args) => err ? [] : [{ type: 'SpaceCustomPerm', id: `ACROSS-${args.spaceId}` }],
    }),
    savePoliciesToAllOwnedSpaces: build.mutation<void, { policies: ISpacePermissionPolicyVo[] }>({
      query: (data) => ({
        url: 'api/v1/space/permission/savePoliciesToAllOwnedSpaces',
        data,
        method: 'POST',
      }),
      invalidatesTags: (_res, err) => err ? [] : [{ type: 'SpaceCustomPerm' }],
    }),
    getSpaceManager: build.query<IMainAdminInfo, { spaceId: string }>({
      query: ({ spaceId }) => ({
        url: 'apitable/api/v1/space/manager',
        headers: {
          'x-space-id': spaceId,
        },
      }),
      providesTags: (_res, err, args) => err ? [] : [{ type: 'SpaceInfo', id: args.spaceId }],
    }),
  }),
  overrideExisting: 'throw',
});

export const {
  /** 获取空间站列表 */
  useGetSpaceListQuery,
  /** 修改空间站停用状态 */
  useUpdateHiddenInfoMutation,
  /** 创建空间站 */
  useCreateSpaceMutation,
  /** 获取空间站信息 */
  useGetSpaceInfoQuery,
  /** 修改空间站名称 */
  useRenameSpaceMutation,
  /** 获取可迁移到的空间站列表，复制外网文档到内网用 */
  useGetManagedSpacesForMigrationQuery,
  /** 超级管理员获取所有空间站列表 */
  useListSpaceBySuperQuery,
  /** 超级管理员修改空间站管理员 */
  useReplaceManagerBySuperMutation,
  /** 获取空间站安全设置 */
  useGetSpaceSecuritySettingQuery,
  /** 修改空间站安全设置 */
  useUpdateSpaceSecuritySettingMutation,
  /** 获取权限和角色枚举值列表 */
  // useListPermissionCodesAndRoleTagsQuery,
  /** 获取空间站自定义权限配置 */
  useGetPermissionPoliciesQuery,
  /** 保存空间站自定义权限配置 */
  useSavePermissionPoliciesMutation,
  /** 保存空间站自定义权限配置到主管理员的所有空间站 */
  useSavePoliciesToAllOwnedSpacesMutation,
  /** 获取空间站跨表权限 */
  useGetCrossTablePermissionsQuery,
  /** 保存空间站跨表权限 */
  useSaveCrossTablePermissionsMutation,
  /** 获取空间站主管理员信息 */
  useGetSpaceManagerQuery,
} = spaceApi;

/** 从空间站列表获取空间站信息 */
export const useSpaceListInfo = (spaceId: string, showForbidSpace = false) => {
  const { data } = useGetSpaceListQuery();
  return useMemo(() => {
    if (!data) return undefined;
    return data.managedSpaces.find((it) => it.spaceId === spaceId)
      ?? data.joinedSpaces.find((it) => it.spaceId === spaceId)
      ?? (showForbidSpace ? data.forbidSpaces.find((it) => it.spaceId === spaceId) : undefined);
  }, [data, showForbidSpace, spaceId]);
};

