package com.yottastudios.ns.collabspace.control.infrastructure.role;

import com.yottastudios.ns.collabspace.control.infrastructure.permission.NodePermission;
import com.yottastudios.ns.collabspace.control.infrastructure.permission.PermissionDefinition;
import com.yottastudios.ns.collabspace.control.infrastructure.policy.SpacePermissionPolicy;

import java.util.*;
import java.util.stream.Collectors;

/**
 * 基于 SpacePermissionPolicy 强制覆盖原 ControlRole 的 Permissions
 */
public class SpacePolicyEnforcedControlRole extends AbstractControlRole {

    private final ControlRole delegate;
    private final SpacePermissionPolicy policy;

    public SpacePolicyEnforcedControlRole(ControlRole delegate,
                                          SpacePermissionPolicy policy) {
        super(delegate.isInherit());
        this.delegate = delegate;
        this.policy = policy;
    }

    @Override
    public String getRoleTag() {
        return delegate.getRoleTag();
    }

    @Override
    public boolean isAdmin() {
        return delegate.isAdmin();
    }

    @Override
    public Set<PermissionDefinition> getPermissions() {
        Set<PermissionDefinition> base = delegate.getPermissions();
        if (policy == null) {
            return base;
        }
        return applyPolicy(base, delegate.getRoleTag());
    }

    @Override
    public Set<PermissionDefinition> getPermissions(String nodeId) {
        Set<PermissionDefinition> base = delegate.getPermissions(nodeId);
        if (policy == null) {
            return base;
        }
        return applyPolicy(base, delegate.getRoleTag());
    }

    private Set<PermissionDefinition> applyPolicy(Set<PermissionDefinition> base, String selfRoleTag) {
        Set<NodePermission> baseNodePerms = extractNodePermissions(base);
        Set<NodePermission> effectiveNodePerms = new HashSet<>();

        Map<String, String> minRoleByCode = policy.asMap();

        for (NodePermission p : NodePermission.values()) {
            String code = p.getCode();
            String minRoleTag = minRoleByCode.get(code);
            if (minRoleTag != null) {
                if (roleGreaterOrEqual(selfRoleTag, minRoleTag)) {
                    effectiveNodePerms.add(p);
                }
                continue;
            }
            if (baseNodePerms.contains(p)) {
                effectiveNodePerms.add(p);
            }
        }

        return mergePermissions(base, effectiveNodePerms);
    }

    private boolean roleGreaterOrEqual(String selfTag, String requiredTag) {
        if (requiredTag == null) return true;
        ControlRole self = ControlRoleManager.parseNodeRole(selfTag);
        ControlRole required = ControlRoleManager.parseNodeRole(requiredTag);
        return self != null && required != null && self.isGreaterThanOrEqualTo(required);
    }

    private Set<NodePermission> extractNodePermissions(Set<PermissionDefinition> defs) {
        Set<NodePermission> r = new HashSet<>();
        for (PermissionDefinition d : defs) {
            if (d instanceof NodePermission) {
                r.add((NodePermission) d);
            }
        }
        return r;
    }

    private Set<PermissionDefinition> mergePermissions(Set<PermissionDefinition> base,
                                                       Set<NodePermission> effectiveNodePerms) {
        Set<PermissionDefinition> merged = new HashSet<>();
        for (PermissionDefinition d : base) {
            if (d instanceof NodePermission) continue;
            merged.add(d);
        }
        merged.addAll(effectiveNodePerms);
        return merged;
    }

    @Override
    public Map<Integer, Long> getGroupPermissionBit() {
        Set<PermissionDefinition> effective = getPermissions();
        Map<Integer, List<PermissionDefinition>> mapGroups = effective.stream().distinct()
                .sorted(Comparator.comparing(PermissionDefinition::getGroup))
                .collect(Collectors.groupingBy(PermissionDefinition::getGroup, Collectors.toList()));
        Map<Integer, Long> bits = new HashMap<>();
        for (Map.Entry<Integer, List<PermissionDefinition>> e : mapGroups.entrySet()) {
            long v = 0L;
            for (PermissionDefinition pd : e.getValue()) {
                v |= pd.getValue();
            }
            bits.put(e.getKey(), v);
        }
        return bits;
    }

    @Override
    public long getBits() {
        return getGroupPermissionBit().values().stream().reduce(0L, (left, right) -> left | right);
    }

    @Override
    public boolean hasPermission(PermissionDefinition permission) {
        return getPermissions().contains(permission);
    }
}
